/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `user_sessions` (
  `session_id` int NOT NULL AUTO_INCREMENT COMMENT 'Unique session identifier',
  `user_id` int NOT NULL COMMENT 'Reference to user',
  `session_token_hash` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Hashed session token for security',
  `device_info` json DEFAULT NULL COMMENT 'Device information (browser, IP, etc.)',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Session creation timestamp',
  `last_active_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Last activity timestamp',
  `is_active` tinyint(1) DEFAULT '1' COMMENT 'Session active status',
  PRIMARY KEY (`session_id`),
  UNIQUE KEY `session_token_hash` (`session_token_hash`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_last_active_at` (`last_active_at`),
  KEY `idx_user_active` (`user_id`,`is_active`),
  CONSTRAINT `fk_user_sessions_user_id` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=242 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Active user sessions for authentication';
